from contextlib import contextmanager
from typing import Optional, Callable, List
from datetime import datetime

class VLLMServer:
    """vLLM server manager for Voxtral models."""

    def __init__(
        self,
        model: str = "mistralai/Voxtral-Mini-3B-2507", # Model name to serve
        port: int = 8000, # Port for the server
        host: str = "0.0.0.0", # Host address to bind to
        gpu_memory_utilization: float = 0.85, # Fraction of GPU memory to use
        log_level: str = "INFO", # Logging level (DEBUG, INFO, WARNING, ERROR)
        capture_logs: bool = True, # Whether to capture and display server logs
        **kwargs # Additional vLLM server arguments
    ):
        self.model = model
        self.port = port
        self.host = host
        self.base_url = f"http://localhost:{self.port}"
        self.process: Optional[subprocess.Popen] = None
        self.capture_logs = capture_logs
        self.log_level = log_level
        
        # Log management
        self.log_queue = queue.Queue()
        self.log_thread = None
        self.stop_logging = threading.Event()
        self.log_callbacks: List[Callable] = []
        
        # Build command
        # Use sys.executable instead of "python"
        # This ensures we use the exact same environment the worker is running in
        self.cmd = [
            sys.executable, "-m", "vllm.entrypoints.openai.api_server",
            "--model", model,
            "--port", str(self.port),
            "--host", host,
            "--gpu-memory-utilization", str(gpu_memory_utilization),
            "--tokenizer-mode", "mistral",
            "--config-format", "mistral",
            "--load-format", "mistral",
        ]
        
        for key, value in kwargs.items():
            self.cmd.extend([f"--{key.replace('_', '-')}", str(value)])
    
    def add_log_callback(
        self, 
        callback: Callable[[str], None] # Function that receives log line strings
    ) -> None: # Returns nothing
        """Add a callback function to receive each log line."""
        self.log_callbacks.append(callback)
    
    def _process_log_line(
        self, 
        line: str # Log line to process
    ) -> None: # Returns nothing
        """Process a single log line."""
        if not line.strip():
            return
        
        # Add timestamp if not present
        if not re.match(r'^\d{2}-\d{2} \d{2}:\d{2}:\d{2}', line):
            timestamp = datetime.now().strftime("%m-%d %H:%M:%S")
            line = f"{timestamp} {line}"
        
        # Store in queue for retrieval
        self.log_queue.put(line)
        
        # Call callbacks
        for callback in self.log_callbacks:
            try:
                callback(line)
            except Exception as e:
                print(f"Error in log callback: {e}")
        
        # Print if we're capturing logs
        if self.capture_logs:
            print(line)
    
    def _log_reader(
        self, 
        pipe, # Pipe to read from
        pipe_name: str # Name of the pipe (stdout/stderr)
    ) -> None: # Returns nothing
        """Read logs from a pipe in a separate thread."""
        for line in iter(pipe.readline, ''):
            if self.stop_logging.is_set():
                break
            if line:
                # Add pipe identifier for debugging
                if pipe_name == "stderr" and "INFO" in line:
                    # Most INFO logs come through stderr in vLLM
                    self._process_log_line(line.strip())
                elif pipe_name == "stdout":
                    self._process_log_line(line.strip())
    
    def start(
        self,
        wait_for_ready: bool = True,                                 # Wait for server to be ready before returning
        show_progress: bool = True,                                  # Show progress indicators during startup
        report_progress: Optional[Callable[[float, str], None]] = None,  # Substrate's PluginInterface.report_progress; defeats prefetch stall detection
    ) -> None: # Returns nothing
        """Start the vLLM server.

        Session A 2026-05-27: dropped the wall-clock `timeout` argument — startup
        time is unbounded (model download + CUDA graph capture), and any operator-
        set value would either race a slow network or be conservatively huge. The
        substrate's proxy.prefetch now drives stall detection via the
        report_progress callback (no progress update for SubstrateConfig.
        prefetch_stall_threshold_seconds → substrate SIGTERMs the worker). When
        report_progress is None we still loop forever; only the OS / operator can
        abort.
        """
        if self.is_running():
            print("Server is already running")
            return
        
        print(f"Starting vLLM server with model {self.model}...")
        print(f"Command: {' '.join(self.cmd)}") # Log the command for debugging
        
        # Start process with pipes for output capture
        self.process = subprocess.Popen(
            self.cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            bufsize=1,  # Line buffered
            universal_newlines=True,
            # Removed preexec_fn as it can be unstable in some nested process scenarios
            # preexec_fn=lambda: signal.signal(signal.SIGINT, signal.SIG_IGN)
        )
        
        # Start log reading threads
        self.stop_logging.clear()
        
        if self.capture_logs:
            # Create threads for reading stdout and stderr
            stdout_thread = threading.Thread(
                target=self._log_reader,
                args=(self.process.stdout, "stdout"),
                daemon=True
            )
            stderr_thread = threading.Thread(
                target=self._log_reader,
                args=(self.process.stderr, "stderr"),
                daemon=True
            )
            stdout_thread.start()
            stderr_thread.start()
        
        # Register cleanup on exit
        atexit.register(self.stop)
        
        if wait_for_ready:
            self._wait_for_server(show_progress, report_progress=report_progress)
    
    def _wait_for_server(
        self,
        show_progress: bool,                                          # Whether to print phase indicators
        report_progress: Optional[Callable[[float, str], None]] = None,  # Substrate's report_progress callback; called on every log line
    ) -> None: # Returns nothing
        """Wait for server to be ready to accept requests.

        Session A 2026-05-27: no wall-clock timeout — loops until the server's
        /health returns 200 OR the vLLM Popen exits non-zero. On each log line
        consumed, calls report_progress(0.5, phase_or_line_summary) — the
        substrate's proxy.prefetch polls /progress and SIGTERMs the worker if
        the (progress, message) tuple stops advancing for
        SubstrateConfig.prefetch_stall_threshold_seconds. Operator-tunable
        substrate-side; the plugin no longer carries a server_startup_timeout
        field (operators were racing arbitrary timeouts against network speeds
        for the model download).
        """
        last_status = ""
        last_line_summary: Optional[str] = None
        start_time = time.time()
        phases = {
            "detected platform": "🔍 Detecting platform...",
            "Loading model": "📦 Loading model weights...",
            "downloading weights": "⬇️ Downloading model weights...",
            "Loading weights took": "✅ Model weights loaded",
            "Graph capturing": "📊 Capturing CUDA graphs...",
            "Graph capturing finished": "✅ CUDA graphs ready",
            "Starting vLLM API server": "🚀 Starting API server...",
            "Available routes": "✅ Server ready!",
        }

        while True:
            # Drain a log line if available; advance phase.
            try:
                log_line = self.log_queue.get_nowait()
            except queue.Empty:
                log_line = None
            if log_line:
                detected_status: Optional[str] = None
                for key, status_msg in phases.items():
                    if key in log_line:
                        detected_status = status_msg
                        break
                if show_progress and detected_status and detected_status != last_status:
                    print(f"\n  {detected_status}")
                    last_status = detected_status
                last_line_summary = detected_status or log_line[:120]

            # Heartbeat: report progress EVERY iteration with elapsed time embedded
            # in the message so the (progress, message) tuple ALWAYS advances. This
            # is the stall-detection contract — substrate.proxy.prefetch SIGTERMs
            # the worker only when /progress STOPS advancing (the loop itself wedged
            # / worker died). vLLM is silent for many seconds during HF Hub
            # download setup; without this heartbeat, the substrate would SIGTERM
            # a perfectly-fine plugin just because vLLM hadn't started emitting
            # logs yet.
            if report_progress is not None:
                elapsed = time.time() - start_time
                summary = last_line_summary or last_status or "awaiting vLLM startup logs"
                try:
                    report_progress(0.5, f"vLLM ({elapsed:.1f}s): {summary}")
                except Exception:
                    # report_progress is best-effort plumbing; never let it
                    # break server startup.
                    pass

            # Ready check.
            try:
                response = requests.get(f"{self.base_url}/health", timeout=1)
                if response.status_code == 200:
                    print(f"\n✅ vLLM server is ready at {self.base_url}")
                    if report_progress is not None:
                        try:
                            report_progress(1.0, f"vLLM server ready at {self.base_url}")
                        except Exception:
                            pass
                    return
            except requests.exceptions.RequestException:
                pass

            # Crash reporting (substrate's Popen.poll-on-crash check).
            if self.process.poll() is not None:
                stdout, stderr = self.process.communicate()
                error_msg = f"Server process exited with code {self.process.poll()}"
                if stdout: error_msg += f"\n[STDOUT]:\n{stdout}"
                if stderr: error_msg += f"\n[STDERR]:\n{stderr}"
                print(error_msg)  # Tee to worker log
                # SG-47: server process exited during startup — fatal; operator must fix
                raise PluginFatalError(error_msg)

            time.sleep(0.5)
    
    def stop(self) -> None: # Returns nothing
        """Stop the vLLM server."""
        if self.process and self.process.poll() is None:
            print("Stopping vLLM server...")
            
            # Signal threads to stop
            self.stop_logging.set()
            
            # Terminate process
            self.process.terminate()
            try:
                self.process.wait(timeout=10)
            except subprocess.TimeoutExpired:
                print("Force killing server...")
                self.process.kill()
                self.process.wait()
            
            self.process = None
            print("Server stopped")
    
    def restart(self) -> None: # Returns nothing
        """Restart the server."""
        self.stop()
        time.sleep(2)
        self.start()
    
    def is_running(self) -> bool: # True if server is running and responsive
        """Check if server is running and responsive."""
        # First check if process exists and hasn't exited
        if self.process is None or self.process.poll() is not None:
            return False
        
        # Try to connect to the server
        try:
            response = requests.get(f"{self.base_url}/health", timeout=1)
            if response.status_code == 200:
                # print(f"\n✅ vLLM server is ready at {self.base_url}")
                return True
            else:
                print(f"\n❌ vLLM server is not ready at {self.base_url}")
                return False
        except requests.exceptions.RequestException as e:
            print(f"\n❌ The following exception occurred: {e}")
            return False
    
    def get_recent_logs(
        self, 
        n: int = 100 # Number of recent log lines to retrieve
    ) -> List[str]: # List of recent log lines
        """Get the most recent n log lines."""
        logs = []
        while not self.log_queue.empty() and len(logs) < n:
            try:
                logs.append(self.log_queue.get_nowait())
            except queue.Empty:
                break
        return logs
    
    def get_metrics_from_logs(self) -> dict: # Dictionary with performance metrics
        """Parse recent logs to extract performance metrics."""
        metrics = {
            "prompt_throughput": 0.0,
            "generation_throughput": 0.0,
            "running_requests": 0,
            "waiting_requests": 0,
            "gpu_kv_cache_usage": 0.0,
            "prefix_cache_hit_rate": 0.0,
        }
        
        # Look for metric lines in recent logs
        recent_logs = self.get_recent_logs(50)
        for log in recent_logs:
            if "Avg prompt throughput:" in log:
                # Parse metrics line
                match = re.search(r'Avg prompt throughput: ([\d.]+) tokens/s', log)
                if match:
                    metrics["prompt_throughput"] = float(match.group(1))
                
                match = re.search(r'Avg generation throughput: ([\d.]+) tokens/s', log)
                if match:
                    metrics["generation_throughput"] = float(match.group(1))
                
                match = re.search(r'Running: (\d+) reqs', log)
                if match:
                    metrics["running_requests"] = int(match.group(1))
                
                match = re.search(r'Waiting: (\d+) reqs', log)
                if match:
                    metrics["waiting_requests"] = int(match.group(1))
                
                match = re.search(r'GPU KV cache usage: ([\d.]+)%', log)
                if match:
                    metrics["gpu_kv_cache_usage"] = float(match.group(1))
                
                match = re.search(r'Prefix cache hit rate: ([\d.]+)%', log)
                if match:
                    metrics["prefix_cache_hit_rate"] = float(match.group(1))
                
                break  # Use the most recent metrics
        
        return metrics
    
    def tail_logs(
        self, 
        follow: bool = True, # Continue displaying new logs as they arrive
        n: int = 10 # Number of initial lines to display
    ) -> None: # Returns nothing
        """Tail the server logs (similar to tail -f)."""
        # Display recent logs
        recent = self.get_recent_logs(n)
        for line in recent:
            print(line)
        
        if follow:
            print("\n--- Following logs (Ctrl+C to stop) ---\n")
            try:
                while self.is_running():
                    if not self.log_queue.empty():
                        print(self.log_queue.get())
                    else:
                        time.sleep(0.1)
            except KeyboardInterrupt:
                print("\n--- Stopped following logs ---")
    
    def __enter__(self):
        """Context manager entry."""
        self.start()
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit."""
        self.stop()

