@patch
def supports_streaming(
    self: VoxtralVLLMPlugin # The plugin instance
) -> bool: # True if streaming is supported
    """Check if this plugin supports streaming transcription."""
    return True

@patch
def execute_stream(
    self: VoxtralVLLMPlugin, # The plugin instance
    audio: Union[str, Path], # Audio data or path to audio file
    **kwargs # Additional plugin-specific parameters
) -> Generator[str, None, TranscriptionResult]: # Yields text chunks, returns final result
    """Stream transcription results chunk by chunk."""
    # Ensure server is running
    self._ensure_server_running()
    
    # Prepare audio file
    audio_path = self._prepare_audio(audio)
    temp_file_created = False  # caller provides a model-ready path; plugin never creates a temp file
    
    try:
        # Get config values, allowing kwargs overrides
        language = kwargs.get("language", self.config.language)
        temperature = kwargs.get("temperature", self.config.temperature)
        
        # Prepare inputs using mistral_common
        self.logger.info(f"Streaming transcription with Voxtral {self.model_id} via vLLM")
        
        input_audio = Audio.from_file(audio_path, strict=False)
        input_audio = RawAudio.from_audio(input_audio)
        
        req = TranscriptionRequest(
            model=self.model_id,
            audio=input_audio,
            language=language or "en",
            temperature=temperature
        ).to_openai(exclude=("top_p", "seed", "target_streaming_delay_ms"))
        
        # Get streaming transcription from vLLM server. SG-47 Track B follow-up:
        # wrap the initial create() call AND the streaming iteration; vLLM
        # subprocess can die at either point. Mid-stream death surfaces as a
        # streaming-response exception when the next chunk is awaited.
        try:
            response = self.client.audio.transcriptions.create(**req, stream=True)
        except Exception as e:
            self._check_vllm_subprocess_death(e, context="streaming transcription start")
            raise

        # Collect generated text. The iteration may raise mid-stream if the
        # vLLM subprocess crashes; same Track B check applies there.
        generated_text = ""
        try:
            for chunk in response:
                if chunk.choices[0]['delta']['content']:
                    text_chunk = chunk.choices[0]['delta']['content']
                    generated_text += text_chunk
                    yield text_chunk
        except Exception as e:
            self._check_vllm_subprocess_death(e, context="streaming transcription iteration")
            raise
        
        # Return final result
        return TranscriptionResult(
            text=generated_text.strip(),
            confidence=None,
            segments=None,
            metadata={
                "model": self.model_id,
                "language": language or "en",
                "server_mode": self.config.server_mode,
                "temperature": temperature,
                "streaming": True,
            }
        )
        
    finally:
        # Clean up temporary file if created
        if temp_file_created:
            try:
                Path(audio_path).unlink()
            except Exception:
                pass
